import React, { useEffect } from "react";
import { useDispatch, useSelector } from "react-redux";
import { useNavigate, useLocation } from "react-router-dom";
import { toast } from "react-toastify";
import * as yup from "yup";
import { useFormik } from "formik";
import { Button, Input } from "antd";
import {
  Save,
  ArrowLeft,
  Tag,
  Ticket,
  Percent,
  Calendar,
  Zap,
  Gift,
  AlertCircle,
} from "lucide-react";
import {
  createCoupon,
  getACoupon,
  resetState,
  updateACoupon,
} from "../features/coupon/couponSlice";

let schema = yup.object().shape({
  name: yup.string().required("Coupon Name is Required"),
  expiry: yup.date().required("Expiry Date is Required"),
  discount: yup
    .number()
    .required("Discount Percentage is Required")
    .min(1)
    .max(100),
});

const AddCoupon = () => {
  const dispatch = useDispatch();
  const location = useLocation();
  const navigate = useNavigate();
  const getCouponId = location.pathname.split("/")[3];
  const newCoupon = useSelector((state) => state.coupon);

  const {
    isSuccess,
    isError,
    isLoading,
    createdCoupon,
    couponName,
    couponDiscount,
    couponExpiry,
    updatedCoupon,
  } = newCoupon;

  const changeDateFormet = (date) => {
    if (!date) return "";
    const newDate = new Date(date);
    return newDate.toISOString().split("T")[0];
  };

  useEffect(() => {
    if (getCouponId !== undefined) {
      dispatch(getACoupon(getCouponId));
    } else {
      dispatch(resetState());
    }
  }, [getCouponId]);

  useEffect(() => {
    if (isSuccess && createdCoupon) {
      toast.success("Coupon Created Successfully!");
      navigate("/admin/coupon-list");
    }
    if (isSuccess && updatedCoupon) {
      toast.success("Coupon Updated Successfully!");
      navigate("/admin/coupon-list");
    }
    if (isError) {
      toast.error("Process Failed. Please check your data.");
    }
  }, [isSuccess, isError, isLoading]);

  const formik = useFormik({
    enableReinitialize: true,
    initialValues: {
      name: couponName || "",
      expiry: changeDateFormet(couponExpiry) || "",
      discount: couponDiscount || "",
    },
    validationSchema: schema,
    onSubmit: (values) => {
      if (getCouponId !== undefined) {
        const data = { id: getCouponId, couponData: values };
        dispatch(updateACoupon(data));
        dispatch(resetState());
      } else {
        dispatch(createCoupon(values));
        formik.resetForm();
        setTimeout(() => {
          dispatch(resetState());
        }, 300);
      }
    },
  });

  return (
    <div className="space-y-8 pb-12">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-[28px] font-bold text-black">
            {getCouponId !== undefined
              ? "Edit Discount Code"
              : "Add Promotion Code"}
          </h1>
          <p className="text-[15px] text-slate-500 mt-1">
            Create special offers and discounts for your patients.
          </p>
        </div>
        <div className="flex items-center gap-3">
          <Button
            onClick={() => navigate(-1)}
            className="h-11 rounded-xl font-bold flex items-center gap-2 border-slate-200 text-slate-600 px-6 hover:bg-slate-50"
          >
            <ArrowLeft size={18} /> Cancel
          </Button>
          <Button
            onClick={() => formik.submitForm()}
            className="h-11 rounded-xl font-bold flex items-center gap-2 bg-[#1e3a8a] text-white border-none px-8 hover:bg-[#1e3a8a]/90 transition-all shadow-sm"
            loading={isLoading}
          >
            <Save size={18} />{" "}
            {getCouponId !== undefined ? "Update Coupon" : "Deploy Coupon"}
          </Button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2">
          <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
            <div className="px-8 py-6 border-b border-slate-50 flex items-center gap-3">
              <div className="p-2 bg-blue-50 rounded-lg">
                <Ticket size={20} className="text-blue-600" />
              </div>
              <h3 className="text-[18px] font-bold text-black">
                Coupon Configuration
              </h3>
            </div>

            <div className="p-8 space-y-8">
              <div className="space-y-2">
                <label className="text-[14px] font-bold text-black pl-1 flex items-center gap-2">
                  Coupon Name / Code
                </label>
                <Input
                  placeholder="e.g. WELCOME10, SUMMER-SALE"
                  className="h-12 rounded-xl border-slate-200 focus:ring-2 focus:ring-blue-500/20 font-bold text-black text-[16px] uppercase placeholder:normal-case"
                  onChange={formik.handleChange("name")}
                  value={formik.values.name}
                />
                {formik.touched.name && formik.errors.name && (
                  <p className="text-rose-500 text-[12px] font-bold mt-1 pl-1">
                    {formik.errors.name}
                  </p>
                )}
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-2">
                  <label className="text-[14px] font-bold text-black pl-1">
                    Expiry Date
                  </label>
                  <Input
                    type="date"
                    className="h-12 rounded-xl border-slate-200 focus:ring-2 focus:ring-blue-500/20 font-medium text-black"
                    onChange={formik.handleChange("expiry")}
                    value={formik.values.expiry}
                  />
                  {formik.touched.expiry && formik.errors.expiry && (
                    <p className="text-rose-500 text-[12px] font-bold mt-1 pl-1">
                      {formik.errors.expiry}
                    </p>
                  )}
                </div>

                <div className="space-y-2">
                  <label className="text-[14px] font-bold text-black pl-1">
                    Discount Percentage
                  </label>
                  <Input
                    type="number"
                    placeholder="e.g. 15"
                    className="h-12 rounded-xl border-slate-200 focus:ring-2 focus:ring-blue-500/20 font-bold text-black"
                    onChange={formik.handleChange("discount")}
                    value={formik.values.discount}
                    suffix={<Percent size={16} className="text-slate-400" />}
                  />
                  {formik.touched.discount && formik.errors.discount && (
                    <p className="text-rose-500 text-[12px] font-bold mt-1 pl-1">
                      {formik.errors.discount}
                    </p>
                  )}
                </div>
              </div>

              <div className="p-4 rounded-xl bg-blue-50/50 border border-blue-100 flex items-start gap-3">
                <AlertCircle size={18} className="text-blue-600 mt-0.5" />
                <p className="text-[13px] font-medium text-slate-600 leading-relaxed">
                  Coupons will be applied to the subtotal of the customer's
                  cart. Ensure the expiry date is in the future.
                </p>
              </div>
            </div>
          </div>
        </div>

        <div className="space-y-8">
          <div className="bg-[#1e3a8a] rounded-2xl p-8 text-white relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-8 opacity-10 group-hover:scale-110 transition-transform duration-700">
              <Gift size={120} />
            </div>
            <div className="relative z-10">
              <h4 className="text-[18px] font-bold mb-2">Promotion Strategy</h4>
              <p className="text-[14px] text-blue-100/80 leading-relaxed font-medium">
                Offering seasonal discounts can increase patient loyalty and
                brand awareness across your pharmacy.
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AddCoupon;
